    /**
     * Builds an OkHttpClient for cloud API communication.
     * - TLS 1.2+ only
     * - Certificate pinning
     * - No cleartext allowed
     */
    private OkHttpClient buildCloudClient() {
        CertificatePinner certificatePinner = new CertificatePinner.Builder()
                .add(CLOUD_API_HOST,
                        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
                .add(CLOUD_API_HOST,
                        "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
                .build();

        // Only allow modern TLS connection specs — no cleartext
        ConnectionSpec tlsSpec = new ConnectionSpec.Builder(ConnectionSpec.MODERN_TLS)
                .build();

        HttpLoggingInterceptor logging = new HttpLoggingInterceptor(
                message -> Log.d(TAG, "[Cloud] " + message));
        logging.setLevel(HttpLoggingInterceptor.Level.BASIC);

        return new OkHttpClient.Builder()
                .connectionSpecs(Collections.singletonList(tlsSpec))
                .certificatePinner(certificatePinner)
                .protocols(Collections.singletonList(Protocol.HTTP_1_1))
                .connectTimeout(15, TimeUnit.SECONDS)
                .readTimeout(15, TimeUnit.SECONDS)
                .writeTimeout(15, TimeUnit.SECONDS)
                .addInterceptor(new CloudAuthInterceptor())
                .addInterceptor(new CleartextBlockingInterceptor(false))
                .addInterceptor(logging)
                .build();
    }

    /**
     * Builds an OkHttpClient for local network IoT device communication.
     * - Cleartext (HTTP) allowed ONLY for 192.168.x.x addresses.
     * - Shorter timeouts for local network.
     * - An interceptor validates the target is actually on the local network.
     */
    private OkHttpClient buildLocalClient() {
        // Allow both cleartext and TLS for local devices
        // (some newer local devices may support HTTPS)
        ConnectionSpec cleartextSpec = new ConnectionSpec.Builder(ConnectionSpec.CLEARTEXT)
                .build();
        ConnectionSpec tlsSpec = new ConnectionSpec.Builder(ConnectionSpec.MODERN_TLS)
                .build();

        HttpLoggingInterceptor logging = new HttpLoggingInterceptor(
                message -> Log.d(TAG, "[Local] " + message));
        logging.setLevel(HttpLoggingInterceptor.Level.BODY);

        return new OkHttpClient.Builder()
                .connectionSpecs(List.of(tlsSpec, cleartextSpec))
                .protocols(Collections.singletonList(Protocol.HTTP_1_1))
                .connectTimeout(5, TimeUnit.SECONDS)
                .readTimeout(5, TimeUnit.SECONDS)
                .writeTimeout(5, TimeUnit.SECONDS)
                .addInterceptor(new LocalNetworkGuardInterceptor())
                .addInterceptor(logging)
                .build();
    }

