    /**
     * Fetches the list of registered devices from the cloud API.
     */
    @NonNull
    public ApiResult getCloudDevices() {
        Request request = new Request.Builder()
                .url(CLOUD_API_BASE_URL + "/v1/devices")
                .get()
                .build();
        return executeCloud(request);
    }

    /**
     * Registers a new device with the cloud API.
     */
    @NonNull
    public ApiResult registerDeviceCloud(@NonNull String deviceJson) {
        RequestBody body = RequestBody.create(deviceJson, JSON);
        Request request = new Request.Builder()
                .url(CLOUD_API_BASE_URL + "/v1/devices")
                .post(body)
                .build();
        return executeCloud(request);
    }

