    @NonNull
    public ApiResult sendCloudCommand(@NonNull String deviceId, @NonNull String commandJson) {
        RequestBody body = RequestBody.create(commandJson, JSON);
        Request request = new Request.Builder()
                .url(CLOUD_API_BASE_URL + "/v1/devices/" + deviceId + "/commands")
                .post(body)
                .build();
        return executeCloud(request);
    }

