    /**
     * Determines whether to use HTTP or HTTPS for a local device.
     * Prefers HTTPS; falls back to HTTP only for known legacy ports.
     */
    @NonNull
    private String resolveLocalScheme(@NonNull String deviceIp, int port) {
        // Port 443 or 8443 → always HTTPS
        if (port == 443 || port == 8443) {
            return "https";
        }
        // Port 80 or 8080 on local network → HTTP (legacy devices)
        if (port == 80 || port == 8080) {
            return "http";
        }
        // Default to HTTPS for any other port
        return "https";
    }

    // ----------------------------------------------------------------
