    /**
     * Interceptor that adds authorization headers for cloud API requests.
     */
    private static class CloudAuthInterceptor implements Interceptor {

        @NonNull
        @Override
        public Response intercept(@NonNull Chain chain) throws IOException {
            Request original = chain.request();
            Request authenticated = original.newBuilder()
                    .header("Authorization", "Bearer " + getApiToken())
                    .header("Accept", "application/json")
                    .header("User-Agent", "IoTManager-Android/1.0")
                    .build();
            return chain.proceed(authenticated);
        }

        private static String getApiToken() {
            // In production, retrieve from secure storage (e.g., EncryptedSharedPreferences)
            return "PLACEHOLDER_TOKEN";
        }
    }

    /**
     * Interceptor that blocks cleartext requests when configured to do so.
     * Acts as an application-level safeguard on top of the network security config.
     */
    private static class CleartextBlockingInterceptor implements Interceptor {

        private final boolean allowCleartext;

        CleartextBlockingInterceptor(boolean allowCleartext) {
            this.allowCleartext = allowCleartext;
        }

        @NonNull
        @Override
        public Response intercept(@NonNull Chain chain) throws IOException {
            Request request = chain.request();
            String scheme = request.url().scheme();

            if (!allowCleartext && "http".equalsIgnoreCase(scheme)) {
                throw new IOException(
                        "Cleartext HTTP is not permitted for this client. URL: " + request.url());
            }
            return chain.proceed(request);
        }
    }

    /**
     * Interceptor that ensures the local client only communicates with
     * addresses on the local 192.168.x.x network. Prevents misuse of
     * the cleartext-capable client for non-local traffic.
     */
    private static class LocalNetworkGuardInterceptor implements Interceptor {

        @NonNull
        @Override
        public Response intercept(@NonNull Chain chain) throws IOException {
            Request request = chain.request();
            String host = request.url().host();

            // Resolve hostname to IP if needed and validate
            if (!isLocalNetworkAddress(host)) {
                // Try resolving DNS in case it's a .local hostname
                try {
                    InetAddress address = InetAddress.getByName(host);
                    String ip = address.getHostAddress();
                    if (ip == null || !isLocalNetworkAddress(ip)) {
                        throw new IOException(
                                "Local client may only communicate with 192.168.x.x addresses. "
                                        + "Attempted: " + host + " (resolved: " + ip + ")");
                    }
                } catch (IOException e) {
                    throw new IOException(
                            "Local client may only communicate with 192.168.x.x addresses. "
                                    + "Attempted: " + host, e);
                }
            }

            // Warn if cleartext is used (but allow it for legacy devices)
            if ("http".equalsIgnoreCase(request.url().scheme())) {
                Log.w(TAG, "Cleartext HTTP request to local device: " + host
                        + ". Consider upgrading device firmware to support HTTPS.");
            }

            return chain.proceed(request);
        }
    }

    // ----------------------------------------------------------------
