    /**
     * Simple result wrapper for API calls.
     */
    public static class ApiResult {

        private final int statusCode;
        @Nullable
        private final String body;
        @Nullable
        private final IOException error;

        public ApiResult(int statusCode, @Nullable String body, @Nullable IOException error) {
            this.statusCode = statusCode;
            this.body = body;
            this.error = error;
        }

        public boolean isSuccessful() {
            return statusCode >= 200 && statusCode < 300;
        }

        public boolean isError() {
            return error != null || statusCode < 0;
        }

        public int getStatusCode() {
            return statusCode;
        }

        @Nullable
        public String getBody() {
            return body;
        }

        @Nullable
        public IOException getError() {
            return error;
        }

        @NonNull
        @Override
        public String toString() {
            if (error != null) {
                return "ApiResult{error=" + error.getMessage() + "}";
            }
            return "ApiResult{status=" + statusCode + ", bodyLength="
                    + (body != null ? body.length() : 0) + "}";
        }
    }

